#!/usr/bin/env python3
"""Clean up files that are no longer generated by openapi-generator.

Compares the old FILES manifest (.openapi-generator/FILES.old) with the new one
(.openapi-generator/FILES) and removes files that exist in the old manifest but
not in the new one.

Usage:
    python scripts/cleanup_obsolete_files.py           # Interactive mode
    python scripts/cleanup_obsolete_files.py --force    # Force mode (no confirmation)
    python scripts/cleanup_obsolete_files.py -f         # Force mode (short form)
"""

from __future__ import annotations

import sys
from pathlib import Path

PROJECT_ROOT = Path(__file__).resolve().parent.parent
FILES_PATH = PROJECT_ROOT / ".openapi-generator" / "FILES"
OLD_FILES_PATH = PROJECT_ROOT / ".openapi-generator" / "FILES.old"

# Directories to exclude from cleanup (never delete test files)
EXCLUDE_PREFIXES = ("tests/", "test/")



def read_manifest(path: Path) -> set[str]:
    """Read a FILES manifest and return a set of non-empty lines."""
    if not path.exists():
        return set()
    return {line.strip() for line in path.read_text().splitlines() if line.strip()}


def main() -> int:
    force_mode = "--force" in sys.argv or "-f" in sys.argv

    if not OLD_FILES_PATH.exists():
        print(f"No old FILES manifest found at {OLD_FILES_PATH}")
        print("This is expected on first run. Skipping cleanup.")
        return 0

    if not FILES_PATH.exists():
        print(f"Error: New FILES manifest not found at {FILES_PATH}")
        print("Make sure the OpenAPI generator has run successfully.")
        return 1

    print("Comparing old and new FILES manifests...")

    old_files = read_manifest(OLD_FILES_PATH)
    new_files = read_manifest(FILES_PATH)

    # Find obsolete files, excluding protected directories
    obsolete = sorted(
        f
        for f in (old_files - new_files)
        if not any(f.startswith(prefix) for prefix in EXCLUDE_PREFIXES)
    )

    if not obsolete:
        print("No obsolete files found. All files are up to date.")
        return 0

    print(f"Found {len(obsolete)} obsolete file(s):")
    for f in obsolete:
        print(f"  {f}")
    print()

    if not force_mode:
        try:
            reply = input("Do you want to delete these files? (y/N): ").strip().lower()
        except (EOFError, KeyboardInterrupt):
            print("\nCleanup cancelled.")
            return 0

        if reply not in ("y", "yes"):
            print("Cleanup cancelled.")
            return 0
    else:
        print("Force mode enabled. Proceeding with deletion...")

    deleted = 0
    not_found = 0

    for filepath_str in obsolete:
        filepath = PROJECT_ROOT / filepath_str
        if filepath.is_file():
            filepath.unlink()
            print(f"  Deleted: {filepath.relative_to(PROJECT_ROOT)}")
            deleted += 1

            # Clean up empty parent directories
            parent = filepath.parent
            while parent != PROJECT_ROOT and parent.exists() and not any(parent.iterdir()):
                parent.rmdir()
                print(f"  Removed empty directory: {parent.relative_to(PROJECT_ROOT)}")
                parent = parent.parent
        else:
            print(f"  Skipping (not found): {filepath_str}")
            not_found += 1

    print()
    print("Cleanup complete!")
    print(f"  Deleted: {deleted} file(s)")
    if not_found:
        print(f"  Not found: {not_found} file(s)")

    return 0


if __name__ == "__main__":
    sys.exit(main())
